import Typography from '@dynatrace/strato-design-tokens/typography';

import { getTokenComputedStyle } from '../../../../../utils/getTokenComputedStyle.js';

const MARKER_FONT_FAMILY = Typography.Text.Small.Emphasized.Family;
const MARKER_FONT_WEIGHT = Typography.Text.Small.Emphasized.Weight;
const MARKER_FONT_SIZE = Typography.Text.Small.Emphasized.Size;

export const getMarkerFont = (() => {
  let markerFont: {
    fontFamily: string;
    fontWeight: string;
    fontSize: string;
  };

  return () => {
    if (!markerFont) {
      const fontSize = getTokenComputedStyle(MARKER_FONT_SIZE);
      const fontFamily = getTokenComputedStyle(MARKER_FONT_FAMILY);
      const fontWeight = getTokenComputedStyle(MARKER_FONT_WEIGHT);
      markerFont = { fontFamily, fontWeight, fontSize };
    }
    return markerFont;
  };
})();
